import React from "react";

const Privacy = () => {
  return (
    <div>
      <h2>Privacy Policy</h2>
      <p>No facial images are stored.</p>
      <p>Only age, gender, and emotion metadata are saved.</p>
      <p>User consent is required before scanning.</p>
    </div>
  );
};

export default Privacy;
